//				popupParam : { closeCallbackFncName : "scwin.uploadFileCallback" }
//			};
//			comLib.openPopup($p, "fileUpload", "/ui/common/te/TE001P01.xml", options);
//		};



		//첨부파일다운로드버튼		
		scwin.btn_Download_onclick = function(filePath, saveFileName, fileName){
			//다운로드 경로
			var sendUrl = filePath + "/" + saveFileName;
			fileLib.fileDownload(sendUrl, fileName);
		};

		// 다운로드버튼 클릭
//		scwin.btn_Download_onclick = function(attchFileId){
//			var sendUrl = "file/downloadAtchFile.do";
//			var sendMethod = "post";		//default값은 post임.
//			var XML = {"attchFileId" : "2017104", "fileSn" :  1 };
//			$w.download(sendUrl, XML, sendMethod);
//		}; 

		// 셀 더블클릭 	
		scwin.grd_file_oncelldblclick  = function(row, col) {
			var atchFileId = dlt_file.getCellData( row, "atchFileId" );       	//첨부파일 ID
			var fileSn = dlt_file.getCellData( row, "fileSn" );       	//첨부파일 ID
			var filePath = dlt_file.getCellData(row, "fileSavePath");				//서버에 저장된 파일 경로
			var saveFileName = dlt_file.getCellData( row , "saveFileNm" );			//서버에 저장된 파일명
			var fileName = dlt_file.getCellData(row, "orginlFileNm");		//저장할 파일명

			if (atchFileId != null) {
//				scwin.btn_Download_onclick(attchFileId);
				// filePath : 서버에 저장된 파일 경로
				// saveFileName : 서버에 저장된 파일명
				// fileName : 원본파일명
				scwin.btn_Download_onclick(filePath, saveFileName, fileName);
			}
		};

		/**
		 * 파일등록
		 */
		scwin.btn_Insert_onclick = function() {
			var options = {
					title : "멀티파일 업로드", width : 800, height : 250, 
					popupParam : { closeCallbackFncName : "mutiFileUploadCallback" }
				};
			comLib.openPopup($p, "mutiFileUpload", "/ui/common/te/TE001P02.xml", options);
			/*		
			var insertedIndex = dlt_file.insertRow( );
			grd_file.setFocusedCell( insertedIndex , 0 );

			if ( dlt_file.getRowStatus( insertedIndex ) == "C") {
				var options = {
					title : "첨부파일 업로드", width : 480, height : 200, 
					popupParam : { closeCallbackFncName : "uploadFileCallback" }
				};
				comLib.openPopup($p, "fileUpload", "/ui/common/te/TE001P02.xml", options);
			}
			*/
		};

		scwin.mutiFileUploadCallback = function(fileInfo) {
			console.log ( "upload file Data : " + JSON.stringify(fileInfo));
			var insertedIndex;
			for (var i=0; i<fileInfo.length; i++) {
				insertedIndex = dlt_file.insertRow( );

//				dma_FileBasic.set(insertedIndex, dlt_file.getColumnIndex("orginlFileNm"), fileInfo[i].localFile);
//				dma_FileBasic.set(insertedIndex, dlt_file.getColumnIndex("fileTempPath"), "[UPLOAD_PATH]" +file);
//				dma_FileBasic.setCellData( insertedIndex , dlt_file.getColumnIndex( "idvdinfoInclsYn" ) , "N" );
//				dma_FileBasic.setCellData( insertedIndex , dlt_file.getColumnIndex( "idvdinfoInclsYn" ) , "N" );

				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "orginlFileNm" ) , fileInfo[i].localFile );
				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "idvdinfoInclsYn" ) , "N" );
//				dlt_file.setCellData( insertedIndex , dlt_file.getColumnIndex( "rowStatus" ) , "C" );
				dlt_file.setCellData(insertedIndex, dlt_file.getColumnIndex("tempFileNm"), "[UPLOAD_PATH]" +fileInfo[i].file);
			}
		};

		scwin.btn_Save_onclick = function() {
			comLib.confirm($p, "첨부파일을 저장하시겠습니까?", "saveFileBasicConfirmCallback");
		};

		scwin.saveFileBasicConfirmCallback = function() {
/*
			dma_FileBasic.set("rowStatus", "C");
			var idvdinfoInclsYn = dlt_file.getCellData( grd_file.getFocusedRowIndex() , "idvdinfoInclsYn" );
			dma_FileBasic.set("idvdinfoInclsYn", idvdinfoInclsYn);  
			var option = {id : "sbm_SaveFileInfo"
						, action : "file/uploadAtchFile.do"
						, ref : "data:json,[{'id':'dma_FileBasic','action':'modified','key':'dataFileBasic'}]"
						, submitDoneHandler : "saveFileBasicCallback"
						, isShowMeg : true };
			ajaxLib.executeSubmission($p, option);
*/
			var requestData = {"dlt_file" : dlt_file.getModifiedJSON() };
			var option = {action : "file/insertAtchFile.do"
			               , reqData : requestData
			               , resData : dlt_file
			               , success : "scwin.saveFileBasicCallback"
			               , isShowMeg : false
				            };			
			ajaxLib.executeAjax($p, option);
		};

		scwin.saveFileBasicCallback  = function(resBody) {
			comLib.alert($p, resBody.message.code_name);
			scwin.search();
		};

		/**
		 * 엑셀다운로드	
		 */
		scwin.btn_Excel_onclick = function(){
			comLib.downloadExcel(grd_file, {fileName : "AtchFileList_Data.xlsx"}, []);
		};

	scwin.btn_FileCrypto_onclick = function() {
			var requestData = {};
			var option = {action : "test/testEncDecFile.do"
		               , reqData : requestData
		               , resData : dlt_file
			           , success : "scwin.fileCryptoCallback"
			           , isShowMeg : false
		                 };			
			ajaxLib.executeAjax($p, option);	
	};

	scwin.fileCryptoCallback = function(resBody) {
		comLib.alert($p, resBody.message.code_name);
	}
